49: 	// Note: gnetId is handled by the frontend constructor as: this.gnetId = data.gnetId || null;
50: 	// But the frontend's JSON.stringify/parse in getSaveModelClone() removes null values
51: 	// So we should NOT set gnetId to null here - let it be handled by the cleanup phase
52: 
53: 	// Note: The frontend does NOT set defaults for these properties:
54: 	// - liveNow: copied as-is from input data
55: 	// - refresh: copied as-is from input data
56: 	// - snapshot: copied as-is from input data
57: 	// - scopeMeta: copied as-is from input data
58: 
59: 	// Structure normalizations
60: 	ensureTemplatingExists(dashboard)
61: 	ensureAnnotationsExist(dashboard)
62: 
63: 	// Note: ensurePanelsHaveUniqueIds is called AFTER applyPanelDefaults in migrate()
64: 	// to preserve original panel IDs and match frontend behavior
65: 
66: 	sortPanelsByGridPos(dashboard)
67: 
68: 	// Built-in components
69: 	initMeta(dashboard)
70: 
71: 	// Variable cleanup
72: 	removeNullValuesFromVariables(dashboard)
73: }
