358: // ensureQueryIds ensures all queries have refId
359: func ensureQueryIds(panel map[string]interface{}) {
360: 	targets, ok := panel["targets"].([]interface{})
361: 	if !ok || len(targets) == 0 {
362: 		return
363: 	}
364: 
365: 	// Check if any target is missing refId
366: 	hasMissingRefId := false
367: 	for _, target := range targets {
368: 		if targetMap, ok := target.(map[string]interface{}); ok {
369: 			if targetMap["refId"] == nil {
370: 				hasMissingRefId = true
371: 				break
372: 			}
373: 		}
374: 	}
375: 
376: 	if hasMissingRefId {
377: 		// Find existing refIds
378: 		existingRefIds := make(map[string]bool)
379: 		for _, target := range targets {
380: 			if targetMap, ok := target.(map[string]interface{}); ok {
381: 				if refId, ok := targetMap["refId"].(string); ok {
382: 					existingRefIds[refId] = true
383: 				}
384: 			}
385: 		}
386: 
387: 		// Assign refIds to targets that don't have them
388: 		letters := "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
389: 		letterIndex := 0
390: 
391: 		for _, target := range targets {
392: 			if targetMap, ok := target.(map[string]interface{}); ok {
393: 				if targetMap["refId"] == nil {
394: 					// Find next available refId
395: 					for letterIndex < len(letters) {
396: 						refId := string(letters[letterIndex])
397: 						if !existingRefIds[refId] {
398: 							targetMap["refId"] = refId
399: 							existingRefIds[refId] = true
400: 							break
401: 						}
402: 						letterIndex++
403: 					}
404: 					letterIndex++
405: 				}
406: 			}
407: 		}
408: 	}
409: }
