556: // filterDefaultValues removes properties that match the default values (matches frontend's isEqual logic)
557: func filterDefaultValues(panel map[string]interface{}, originalProperties map[string]bool) {
558: 	// Get panel type for panel-specific defaults
559: 	panelType := ""
560: 	if t, ok := panel["type"].(string); ok {
561: 		panelType = t
562: 	}
563: 
564: 	// PanelModel defaults from frontend
565: 	defaults := map[string]interface{}{
566: 		"gridPos": map[string]interface{}{
567: 			"x": 0, "y": 0, "h": 3, "w": 6,
568: 		},
569: 		"targets": []interface{}{
570: 			map[string]interface{}{"refId": "A"},
571: 		},
572: 		"cachedPluginOptions": map[string]interface{}{},
573: 		"transparent":         false,
574: 		"options":             map[string]interface{}{},
575: 		"links":               []interface{}{},
576: 		"fieldConfig": map[string]interface{}{
577: 			"defaults":  map[string]interface{}{},
578: 			"overrides": []interface{}{},
579: 		},
580: 		"title": "",
581: 	}
582: 
583: 	// Add panel-specific defaults
584: 	if panelType == "table" {
585: 		// Remove legacy table properties (matches frontend getSaveModel filtering)
586: 		// Exception: preserve original properties for old table panels with autoMigrateFrom="table-old"
587: 		legacyTableProps := []string{"pageSize", "scroll", "fontSize", "showHeader", "sort"}
588: 		for _, prop := range legacyTableProps {
589: 			if _, exists := panel[prop]; exists {
590: 				if autoMigrateFrom, hasAutoMigrate := panel["autoMigrateFrom"]; hasAutoMigrate && autoMigrateFrom == "table-old" {
591: 					if !originalProperties[prop] {
592: 						delete(panel, prop)
593: 					}
594: 				} else {
595: 					delete(panel, prop)
596: 				}
597: 			}
598: 		}
599: 	}
600: 
601: 	// Remove properties that match defaults, but preserve properties that were originally present
602: 	for prop, defaultValue := range defaults {
603: 		if panelValue, exists := panel[prop]; exists {
604: 			if isEqual(panelValue, defaultValue) {
605: 				// Special case: fieldConfig - handle preservation of original custom object first
606: 				if prop == "fieldConfig" {
607: 					// Check if we need to preserve the custom object before removing fieldConfig
608: 					if panel["_originallyHadFieldConfigCustom"] == true {
609: 						// Ensure fieldConfig structure exists with custom object
610: 						if fieldConfig, ok := panelValue.(map[string]interface{}); ok {
611: 							if defaults, ok := fieldConfig["defaults"].(map[string]interface{}); ok {
612: 								if _, hasCustom := defaults["custom"]; !hasCustom {
613: 									defaults["custom"] = map[string]interface{}{}
614: 								}
615: 								// Don't remove fieldConfig if we added custom back
616: 								continue
617: 							}
618: 						}
619: 					}
620: 					delete(panel, prop)
621: 				} else {
622: 					// Only remove if it wasn't originally present in the input
623: 					if !originalProperties[prop] {
624: 						delete(panel, prop)
625: 					}
626: 				}
627: 			}
628: 		}
629: 	}
630: 
631: 	// Remove empty targets arrays (frontend removes them in cleanup)
632: 	removeIfDefaultValue(panel, "targets", []interface{}{})
633: 
634: 	// Handle case where fieldConfig was removed but originally had custom object
635: 	if panel["_originallyHadFieldConfigCustom"] == true {
636: 		if _, hasFieldConfig := panel["fieldConfig"]; !hasFieldConfig {
637: 			// Recreate fieldConfig with custom object
638: 			panel["fieldConfig"] = map[string]interface{}{
639: 				"defaults": map[string]interface{}{
640: 					"custom": map[string]interface{}{},
641: 				},
642: 				"overrides": []interface{}{},
643: 			}
644: 		}
645: 	}
646: 
647: 	// Clean up fieldConfig to match frontend behavior
648: 	if fieldConfig, exists := panel["fieldConfig"].(map[string]interface{}); exists {
649: 		// Clean up fieldConfig defaults to match frontend behavior
650: 		if defaults, hasDefaults := fieldConfig["defaults"].(map[string]interface{}); hasDefaults {
651: 			// Remove properties that frontend considers as defaults and omits
652: 			cleanupFieldConfigDefaults(defaults, panel)
653: 
654: 			// Preserve custom object if it was originally present, even if empty
655: 			if panel["_originallyHadFieldConfigCustom"] == true {
656: 				if _, hasCustom := defaults["custom"]; !hasCustom {
657: 					defaults["custom"] = map[string]interface{}{}
658: 				}
659: 			}
660: 		}
661: 	}
662: }
