{"content":"1: import { mergeWith, isArray, isObject, unset, isEqual } from 'lodash';
2: 
3: import { FieldConfigOptionsRegistry } from '../field/FieldConfigOptionsRegistry';
4: import { fieldColorModeRegistry } from '../field/fieldColor';
5: import { FieldColorConfigSettings } from '../field/overrides/processors';
6: import { FieldColorModeId } from '../types/fieldColor';
7: import {
8:   ConfigOverrideRule,
9:   DynamicConfigValue,
10:   FieldConfigProperty,
11:   FieldConfigSource,
12: } from '../types/fieldOverrides';
13: import { ThresholdsConfig, ThresholdsMode } from '../types/thresholds';
14: 
15: import { PanelPlugin } from './PanelPlugin';
16: 
17: interface Props {
18:   plugin: PanelPlugin;
19:   currentFieldConfig: FieldConfigSource;
20:   currentOptions: Record<string, unknown>;
21:   isAfterPluginChange: boolean;
22: }
23: 
24: export interface OptionDefaults {
25:   options: Record<string, unknown>;
26:   fieldConfig: FieldConfigSource;
27: }
28: 
29: /**
30:  * This will return the panel options with defaults applied.
31:  * Used internally, not intended for external use.
32:  * @internal
33:  */
34: export function getPanelOptionsWithDefaults({
35:   plugin,
36:   currentOptions,
37:   currentFieldConfig,
38:   isAfterPluginChange,
39: }: Props): OptionDefaults {
40:   const optionsWithDefaults = mergeWith({}, plugin.defaults, currentOptions || {}, (objValue, srcValue) => {
41:     if (isArray(srcValue)) {
42:       return srcValue;
43:     }
44:     return;
45:   });
46: 
47:   const fieldConfigWithDefaults = applyFieldConfigDefaults(currentFieldConfig, plugin);
48:   const fieldConfigWithOptimalColorMode = adaptFieldColorMode(plugin, fieldConfigWithDefaults, isAfterPluginChange);
49: 
50:   return { options: optionsWithDefaults, fieldConfig: fieldConfigWithOptimalColorMode };
51: }
52: 
53: function applyFieldConfigDefaults(existingFieldConfig: FieldConfigSource, plugin: PanelPlugin): FieldConfigSource {
54:   const pluginDefaults = plugin.fieldConfigDefaults;
55: 
56:   const result: FieldConfigSource = {
57:     defaults: mergeWith(
58:       {},
59:       pluginDefaults.defaults,
60:       existingFieldConfig ? existingFieldConfig.defaults : {},
61:       (objValue, srcValue) => {
62:         if (isArray(srcValue)) {
63:           return srcValue;
64:         }
65:         return;
66:       }
67:     ),
68:     overrides: existingFieldConfig?.overrides ?? [],
69:   };
70: 
71:   cleanProperties(result.defaults, '', plugin.fieldConfigRegistry);
72: 
73:   // Thresholds base values are null in JSON but need to be converted to -Infinity
74:   if (result.defaults.thresholds) {
75:     fixThresholds(result.defaults.thresholds);
76:   }
77: 
78:   // Filter out overrides for properties that cannot be found in registry
79:   result.overrides = filterFieldConfigOverrides(result.overrides, (prop) => {
80:     return plugin.fieldConfigRegistry.getIfExists(prop.id) !== undefined;
81:   });
82: 
83:   for (const override of result.overrides) {
84:     for (const property of override.properties) {
85:       if (property.id === 'thresholds') {
86:         fixThresholds(property.value);
87:       }
88:     }
89:   }
90: 
91:   return result;
92: }
93: 
94: /**
95:  * Used internally, not intended for external use.
96:  * @internal
97:  */
98: export function filterFieldConfigOverrides(
99:   overrides: ConfigOverrideRule[],
100:   condition: (value: DynamicConfigValue) => boolean
101: ): ConfigOverrideRule[] {
102:   return overrides.map((x) => {
103:     const properties = x.properties.filter(condition);
104: 
105:     return {
106:       ...x,
107:       properties,
108:     };
109:   });
110: }
111: 
112: function cleanProperties(obj: object, parentPath: string, fieldConfigRegistry: FieldConfigOptionsRegistry) {
113:   let found = false;
114: 
115:   for (const [propName, value] of Object.entries(obj)) {
116:     const fullPath = `${parentPath}${propName}`;
117:     const existsInRegistry = !!fieldConfigRegistry.getIfExists(fullPath);
118: 
119:     // need to check early here as some standard properties have nested properies
120:     if (existsInRegistry) {
121:       found = true;
122:       continue;
123:     }
124: 
125:     if (isArray(value) || !isObject(value)) {
126:       if (!existsInRegistry) {
127:         unset(obj, propName);
128:       }
129:     } else {
130:       const childPropFound = cleanProperties(value, `${fullPath}.`, fieldConfigRegistry);
131:       // If no child props found unset the main object
132:       if (!childPropFound) {
133:         unset(obj, propName);
134:       }
135:     }
136:   }
137: 
138:   return found;
139: }
140: 
141: function adaptFieldColorMode(
142:   plugin: PanelPlugin,
143:   fieldConfig: FieldConfigSource,
144:   isAfterPluginChange: boolean
145: ): FieldConfigSource {
146:   if (!isAfterPluginChange) {
147:     return fieldConfig;
148:   }
149: 
150:   // adjust to prefered field color setting if needed
151:   const color = plugin.fieldConfigRegistry.getIfExists(FieldConfigProperty.Color);
152: 
153:   if (color && color.settings) {
154:     const colorSettings: FieldColorConfigSettings = color.settings;
155:     const mode = fieldColorModeRegistry.getIfExists(fieldConfig.defaults.color?.mode);
156: 
157:     // When no support fo value colors, use classic palette
158:     if (!colorSettings.byValueSupport) {
159:       if (!mode || mode.isByValue) {
160:         fieldConfig.defaults.color = { mode: FieldColorModeId.PaletteClassic };
161:         return fieldConfig;
162:       }
163:     }
164: 
165:     // When supporting value colors and prefering thresholds, use Thresholds mode.
166:     // Otherwise keep current mode
167:     if (colorSettings.byValueSupport && colorSettings.preferThresholdsMode && mode?.id !== FieldColorModeId.Fixed) {
168:       if (!mode || !mode.isByValue) {
169:         fieldConfig.defaults.color = { mode: FieldColorModeId.Thresholds };
170:         return fieldConfig;
171:       }
172:     }
173: 
174:     // If panel support bySeries then we should default to that when switching to this panel as that is most likely
175:     // what users will expect. Example scenario a user who has a graph panel (time series) and switches to Gauge and
176:     // then back to time series we want the graph panel color mode to reset to classic palette and not preserve the
177:     // Gauge prefered thresholds mode.
178:     if (colorSettings.bySeriesSupport && mode?.isByValue) {
179:       fieldConfig.defaults.color = { mode: FieldColorModeId.PaletteClassic };
180:       return fieldConfig;
181:     }
182:   }
183:   return fieldConfig;
184: }
185: 
186: function fixThresholds(thresholds: ThresholdsConfig) {
187:   if (!thresholds.mode) {
188:     thresholds.mode = ThresholdsMode.Absolute;
189:   }
190: 
191:   if (!thresholds.steps) {
192:     thresholds.steps = [];
193:   } else if (thresholds.steps.length) {
194:     // First value is always -Infinity
195:     // JSON saves it as null
196:     thresholds.steps[0].value = -Infinity;
197:   }
198: }
